import React, { useEffect, useState, useRef } from 'react';
import * as ReactRouterDom from 'react-router-dom';
import { motion as motionBase, AnimatePresence } from 'framer-motion';

const motion = motionBase as any;
const { Link, useLocation, useNavigate } = ReactRouterDom as any;

const Navbar: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [userSession, setUserSession] = useState<any>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);

    const checkSession = () => {
      const stored = localStorage.getItem('visionhaven_session');
      if (stored) {
        setUserSession(JSON.parse(stored));
      } else {
        setUserSession(null);
      }
    };

    checkSession();
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [location]);

  const handleLogout = () => {
    localStorage.removeItem('visionhaven_session');
    setUserSession(null);
    setIsMenuOpen(false);
    navigate('/');
  };

  const isHome = location.pathname === '/';

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-500 ${scrolled ? 'bg-white/95 backdrop-blur-xl py-4 shadow-xl shadow-black/5' : 'bg-transparent py-8'}`}>
      <div className="max-w-[1600px] mx-auto px-8 lg:px-16 flex justify-between items-center">
        <Link to="/" className="flex flex-col group">
          <div className="flex items-center gap-3">
            <div className={`w-8 h-8 flex items-center justify-center border ${!scrolled && isHome ? 'border-white/40' : 'border-luxury-charcoal/20'} rounded-lg group-hover:border-luxury-gold transition-colors`}>
               <svg className="w-5 h-5 text-luxury-gold" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <path d="M3 9.5L12 3L21 9.5V19C21 20.1046 20.1046 21 19 21H5C3.89543 21 3 20.1046 3 19V9.5Z" />
                  <path d="M9 21V12C9 10.3431 10.3431 9 12 9C13.6569 9 15 10.3431 15 12V21" />
               </svg>
            </div>
            <div className="flex flex-col text-left">
              <span className={`text-2xl font-serif font-bold tracking-[0.3em] transition-colors leading-none ${!scrolled && isHome ? 'text-white' : 'text-luxury-charcoal'}`}>
                VISION<span className="opacity-70">HAVEN</span>
              </span>
              <span className="text-[7px] uppercase tracking-[0.4em] text-luxury-gold font-bold mt-1">Envisioning Your Dream Space</span>
            </div>
          </div>
        </Link>

        <div className="hidden md:flex space-x-12 items-center">
          {[
            { name: 'Home', path: '/' },
            { name: 'Gallery', path: '/gallery' },
            { name: 'The Vault', path: '/dashboard?tab=wishlist' },
            { name: 'Contact', path: '/contact' }
          ].map((item) => {
            const isActive = location.pathname === item.path || (item.path.includes('tab=wishlist') && location.search.includes('tab=wishlist'));
            return (
              <Link 
                key={item.name} 
                to={item.path} 
                className={`relative text-[10px] uppercase tracking-[0.35em] font-bold transition-all hover:text-luxury-gold ${!scrolled && isHome ? 'text-white/70' : 'text-zinc-500'} ${isActive ? 'text-luxury-gold' : ''}`}
              >
                {item.name}
                {isActive && (
                  <motion.div 
                    layoutId="nav-underline"
                    className="absolute -bottom-2 left-0 right-0 h-[2px] bg-luxury-gold shadow-[0_0_8px_rgba(197,160,89,0.5)]" 
                  />
                )}
              </Link>
            );
          })}
        </div>

        <div className="flex items-center gap-6 relative" ref={menuRef}>
          {userSession ? (
            <div className="relative">
              <button 
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className={`w-10 h-10 rounded-full border overflow-hidden flex items-center justify-center transition-all ${!scrolled && isHome ? 'border-white/20 hover:border-white/50' : 'border-zinc-200 hover:border-luxury-gold'}`}
              >
                <img 
                  src={userSession.avatarUrl || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userSession.name}`} 
                  alt="Avatar" 
                  className="w-full h-full object-cover"
                />
              </button>

              <AnimatePresence>
                {isMenuOpen && (
                  <motion.div 
                    initial={{ opacity: 0, y: 10, scale: 0.95 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: 10, scale: 0.95 }}
                    className="absolute right-0 mt-4 w-64 bg-white rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] border border-zinc-100 overflow-hidden py-4 z-50"
                  >
                    <div className="px-6 py-4 border-b border-zinc-50 mb-2">
                      <p className="text-[10px] uppercase tracking-widest text-zinc-400 font-bold mb-1">Authenticated As</p>
                      <p className="text-sm font-serif font-bold text-luxury-charcoal truncate">{userSession.name}</p>
                      <p className="text-[9px] text-luxury-gold font-bold uppercase tracking-widest mt-1">{userSession.role} Protocol</p>
                    </div>

                    <Link 
                      to={userSession.role === 'vendor' ? "/vendor" : "/dashboard"} 
                      onClick={() => setIsMenuOpen(false)}
                      className="flex items-center gap-4 px-6 py-3 text-[10px] uppercase tracking-widest font-bold text-zinc-500 hover:text-luxury-gold hover:bg-zinc-50 transition-all"
                    >
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                      {userSession.role === 'vendor' ? 'Command Centre' : 'Studio Dashboard'}
                    </Link>

                    <Link 
                      to="/dashboard?tab=wishlist" 
                      onClick={() => setIsMenuOpen(false)}
                      className="flex items-center gap-4 px-6 py-3 text-[10px] uppercase tracking-widest font-bold text-zinc-500 hover:text-luxury-gold hover:bg-zinc-50 transition-all"
                    >
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                      The Vault
                    </Link>

                    <Link 
                      to="/report" 
                      onClick={() => setIsMenuOpen(false)}
                      className="flex items-center gap-4 px-6 py-3 text-[10px] uppercase tracking-widest font-bold text-zinc-500 hover:text-luxury-gold hover:bg-zinc-50 transition-all"
                    >
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                      Report Issue
                    </Link>

                    <div className="h-[1px] bg-zinc-50 my-2 mx-6"></div>

                    <button 
                      onClick={handleLogout}
                      className="w-full flex items-center gap-4 px-6 py-3 text-[10px] uppercase tracking-widest font-bold text-red-400 hover:bg-red-50 transition-all"
                    >
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
                      Revoke Access
                    </button>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
          ) : (
            <Link 
              to="/login"
              className={`text-[10px] uppercase tracking-[0.3em] font-bold ${!scrolled && isHome ? 'text-white' : 'text-luxury-charcoal'} hover:text-luxury-gold transition-colors`}
            >
              Sign In
            </Link>
          )}

          <Link 
             to="/design" 
             className={`hidden sm:block px-10 py-4 rounded-full text-[10px] uppercase tracking-[0.25em] font-bold transition-all duration-500 shadow-2xl ${!scrolled && isHome ? 'bg-white text-luxury-charcoal hover:bg-luxury-gold hover:text-white' : 'bg-luxury-charcoal text-white hover:bg-luxury-gold shadow-luxury-gold/20'}`}
           >
             Start Visioning
           </Link>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useEffect, useState } from 'react';
import { motion as motionBase, AnimatePresence } from 'framer-motion';
import * as ReactRouterDom from 'react-router-dom';
import { authService } from '../services/authService';

const motion = motionBase as any;
const { useNavigate, useLocation } = ReactRouterDom as any;

const DashboardPage: React.FC = () => {
  const [userSession, setUserSession] = useState<any>(null);
  const [activeTab, setActiveTab] = useState('studio');
  const [projects, setProjects] = useState<any[]>([]);
  const [vault, setVault] = useState<any[]>([]);
  const [history, setHistory] = useState<any[]>([]);
  const [procurement, setProcurement] = useState<any[]>([]);
  const [isUpdating, setIsUpdating] = useState(false);
  const [updateSuccess, setUpdateSuccess] = useState(false);

  const [profileForm, setProfileForm] = useState({
    name: '',
    preferences: 'Luxury Modern'
  });

  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const tabParam = params.get('tab');
    if (tabParam) setActiveTab(tabParam);
  }, [location]);

  useEffect(() => {
    const stored = localStorage.getItem('visionhaven_session');
    if (stored) {
      const session = JSON.parse(stored);
      setUserSession(session);
      setProfileForm({ name: session.name, preferences: 'Luxury Modern' });

      const projectsKey = `vh_projects_${session.id}`;
      const savedProjects = JSON.parse(localStorage.getItem(projectsKey) || '[]');
      setProjects(savedProjects.length > 0 ? savedProjects : [{ id: '1', title: 'Welcome Visualization', date: 'Initial', img: 'https://images.unsplash.com/photo-1600607687920-4e2a09cf159d?q=80&w=800' }]);

      const vaultKey = `vh_vault_${session.id}`;
      const savedVault = JSON.parse(localStorage.getItem(vaultKey) || '[]');
      setVault(savedVault);

      // Mock History
      setHistory([
        { id: 'h1', event: 'Neural Scan Initiated', type: 'System', date: '2 hours ago' },
        { id: 'h2', event: 'Texture Set "Ruby Deep" Applied', type: 'Design', date: 'Yesterday' },
        { id: 'h3', event: 'Project "Penthouse" Archived', type: 'Archive', date: '3 days ago' },
      ]);

      // Mock Procurement
      setProcurement([
        { id: 'p1', name: 'Italian Arabescato Marble', price: '$240/sqm', vendor: 'Carrara Elite' },
        { id: 'p2', name: 'Brushed Brass Fixtures', price: '$1,200', vendor: 'Aureum Fittings' },
      ]);
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsUpdating(true);
    try {
      const updated = await authService.updateUser(userSession.id, { name: profileForm.name });
      const newSession = { ...userSession, name: updated.name };
      localStorage.setItem('visionhaven_session', JSON.stringify(newSession));
      setUserSession(newSession);
      setUpdateSuccess(true);
      setTimeout(() => setUpdateSuccess(false), 3000);
    } catch (err) {
      console.error(err);
    } finally {
      setIsUpdating(false);
    }
  };

  const handleUpdateAvatar = async () => {
    setIsUpdating(true);
    const newSeed = Math.random().toString(36).substring(7);
    const newAvatar = `https://api.dicebear.com/7.x/avataaars/svg?seed=${newSeed}`;
    try {
      const updated = await authService.updateUser(userSession.id, { avatarUrl: newAvatar });
      const newSession = { ...userSession, avatarUrl: updated.avatarUrl };
      localStorage.setItem('visionhaven_session', JSON.stringify(newSession));
      setUserSession(newSession);
    } catch (err) {
      console.error(err);
    } finally {
      setIsUpdating(false);
    }
  };

  const removeFromVault = (id: string) => {
    const vaultKey = `vh_vault_${userSession.id}`;
    const newVault = vault.filter(item => item.id !== id);
    localStorage.setItem(vaultKey, JSON.stringify(newVault));
    setVault(newVault);
  };

  if (!userSession) return null;

  const tabs = [
    { id: 'studio', label: 'My Vision Studio', icon: 'M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10' },
    { id: 'wishlist', label: 'The Vault', icon: 'M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z' },
    { id: 'history', label: 'Neural History', icon: 'M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z' },
    { id: 'procurement', label: 'Procurement', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
    { id: 'settings', label: 'Studio Settings', icon: 'M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z' },
  ];

  return (
    <div className="max-w-[1600px] mx-auto px-8 lg:px-16 pt-32 pb-24 min-h-screen bg-[#FDFBF7]">
      <div className="grid lg:grid-cols-4 gap-12">
        {/* Sidebar */}
        <aside className="lg:col-span-1">
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="p-10 bg-white rounded-[50px] border border-zinc-100 shadow-xl shadow-black/5 mb-8 text-center"
          >
            <div className="relative inline-block mb-6">
              <div className="w-28 h-28 rounded-full overflow-hidden border-4 border-luxury-cream shadow-inner mx-auto group">
                <img 
                  src={userSession.avatarUrl || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userSession.name}`} 
                  alt="Profile" 
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                />
              </div>
              <button 
                onClick={handleUpdateAvatar}
                className="absolute bottom-0 right-0 w-10 h-10 bg-luxury-gold text-white rounded-full flex items-center justify-center border-4 border-white shadow-lg hover:scale-110 transition-transform"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
              </button>
            </div>
            <h3 className="font-serif text-3xl text-luxury-charcoal mb-2">{userSession.name}</h3>
            <div className="inline-block px-5 py-2 bg-luxury-gold/10 rounded-full border border-luxury-gold/20">
              <p className="text-[10px] uppercase tracking-widest font-bold text-luxury-gold">{userSession.role} curator</p>
            </div>
          </motion.div>

          <nav className="space-y-3">
            {tabs.map((tab) => (
              <button 
                key={tab.id} 
                onClick={() => setActiveTab(tab.id)}
                className={`w-full text-left px-8 py-5 rounded-3xl flex items-center gap-5 transition-all ${activeTab === tab.id ? 'bg-luxury-charcoal text-white shadow-2xl scale-[1.02]' : 'bg-white/50 text-zinc-500 hover:bg-white hover:text-luxury-charcoal border border-transparent hover:border-zinc-100'}`}
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d={tab.icon} /></svg>
                <span className="text-[10px] uppercase tracking-widest font-bold">{tab.label}</span>
              </button>
            ))}
          </nav>
        </aside>

        {/* Content Area */}
        <main className="lg:col-span-3">
          <AnimatePresence mode="wait">
            {activeTab === 'studio' && (
              <motion.div key="studio" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="space-y-10">
                <header className="flex justify-between items-end">
                   <div>
                      <h2 className="text-5xl font-serif text-luxury-charcoal">Curated Studio</h2>
                      <p className="text-[10px] uppercase tracking-[0.4em] text-zinc-400 font-bold mt-2">Personal Architectural Archive</p>
                   </div>
                   <button onClick={() => navigate('/design')} className="px-10 py-4 bg-luxury-gold text-white rounded-full text-[10px] uppercase tracking-widest font-bold shadow-xl hover:bg-luxury-charcoal transition-colors">Generate New Vision</button>
                </header>

                <div className="grid md:grid-cols-2 gap-10">
                  {projects.map((p) => (
                    <motion.div key={p.id} whileHover={{ y: -10 }} className="bg-white rounded-[50px] border border-zinc-100 overflow-hidden shadow-xl group">
                       <div className="aspect-video relative overflow-hidden">
                          <img src={p.img} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" alt={p.title} />
                          <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                             <button className="px-8 py-3 bg-white text-luxury-charcoal rounded-full text-[10px] uppercase tracking-widest font-bold">Launch Workbench</button>
                          </div>
                       </div>
                       <div className="p-10">
                          <h4 className="text-2xl font-serif text-luxury-charcoal mb-2">{p.title}</h4>
                          <span className="text-[9px] uppercase tracking-widest text-zinc-300 font-bold">{p.date}</span>
                       </div>
                    </motion.div>
                  ))}
                </div>
              </motion.div>
            )}

            {activeTab === 'wishlist' && (
              <motion.div key="wishlist" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="space-y-10">
